def mode_count(nums):
    if not nums:  # Edge case: empty list returns 0
        return 0

    freq = {}
    max_freq = 0

    for num in nums:
        freq[num] = freq.get(num, 0) + 1
        max_freq = max(max_freq, freq[num])

    return sum(1 for count in freq.values() if count == max_freq)
